qry:select.qry:xquery:
			for $r in sql('
		SELECT 
			LIQ20_TOT_LIQ_PER.oi_tot_liq_per
		FROM 
			LIQ19_LIQUIDACION, LIQ19_EJECUCIONES, 
			LIQ99_LIQUIDACION, LIQ99_RECIBOS, 
			LIQ20_TOT_LIQ_PER, LIQ97_PERSONAL_EMP
		JOIN
		  LIQ19_LIQUIDACION.oi_liquidacion INNER LIQ19_EJECUCIONES.oi_liquidacion,
			LIQ19_EJECUCIONES.oi_liquidacion_ddo INNER LIQ99_LIQUIDACION.oi_liquidacion_ddo,
			LIQ99_LIQUIDACION.oi_liquidacion_ddo INNER LIQ99_RECIBOS.oi_liquidacion_ddo,
			LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_TOT_LIQ_PER.oi_tot_liq_per,
			LIQ20_TOT_LIQ_PER.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo
		WHERE
			LIQ19_LIQUIDACION.e_periodo = {#SOURCE:@e_periodo}
			AND LIQ19_LIQUIDACION.oi_empresa = {#SOURCE:@oi_empresa}
			{%? (#VAL:@noValidarCerradas!='1')
				{% AND LIQ19_LIQUIDACION.c_estado = \'C\' %}
				{% %}
			%}
			{%? (string(#SOURCE:LIQUIDACIONES/LIQUIDACION/@id)!='')         
				{% AND LIQ19_LIQUIDACION.oi_liquidacion 
					{%? (#SOURCE:@excluir=1) 	
						{% NOT IN ({%=string(#SOURCE:LIQUIDACIONES/LIQUIDACION/@id)%}) %} 
						{% IN     ({%=string(#SOURCE:LIQUIDACIONES/LIQUIDACION/@id)%}) %} 
					%}
				%}
				{% %}					
			%}
			AND LIQ99_LIQUIDACION.c_estado = \'F\'
 	')ROWS
